import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"阿斯莫","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/阿斯莫.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/阿斯莫.md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/阿斯莫.md"};function d(l,a,_,b,i,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"阿斯莫",tabindex:"-1"},[n("阿斯莫 "),e("a",{class:"header-anchor",href:"#阿斯莫","aria-label":'Permalink to "阿斯莫"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),s('<h1 id="阿斯莫-1" tabindex="-1">阿斯莫 <a class="header-anchor" href="#阿斯莫-1" aria-label="Permalink to &quot;阿斯莫&quot;">​</a></h1><p>阿斯莫</p><p>价格：1000<br> 本质：魔幻<br> 分类：一次性血统<br> 特殊：不占据血统位<br> 每一名阿斯莫的灵魂承载着天堂之光。他们继承了来自于祖先从天堂山——一处被众多守序善良神祗所守护的神圣领域——所得的一星半点力量。阿斯莫出生被视为一种祝福。他们超凡脱俗的外表和辉赫的面貌揭示了来自天界的遗赠。<br> 阿斯莫在剧情世界种会被视为【光明生物】，每一名阿斯莫都有着超凡脱俗的外表，成为阿斯莫意味着你的容貌获额外得1点加值，自然寿命通常能抵达人类寿命所允许的极限。</p><p>黑暗视觉：拜你的光辉灵魂所赐，你的视觉可以轻易地跨越黑暗，获得【黑暗视觉】。</p><p>阿斯莫向导<br> 每个阿斯莫都会链接着一名天使，除非他已经转向邪恶。他们——通常是一位天神使徒或是其他什么神圣的存在——为阿斯莫把握方向，虽然他们的链接仅仅只在梦中。他们的指导不是直接命令或简单的口语。相反，阿斯莫接收的是异象，预言，和感情。天使并非无所不知。他们的指导往往基于他们所理解的秩序和良善。<br> 选择不同的阿斯莫向导会成为不同的阿斯莫，从以下三类中选择一项：守护阿斯莫、天罚阿斯莫和堕落阿斯莫，这是一种扮演限制。</p><p>守护阿斯莫<br> 守护阿斯莫使用他们的善良力量去保护弱小，打击邪恶，无论它们在何处发生，他们永远警惕着来自黑暗的力量。从青年时开始，一个守护阿斯莫就不断接受到建议和指示：在面对邪恶时挺身而出。<br> 光辉灵魂：你可以使用一个自由动作来释放你内在的神圣能量。这将使你的眼睛闪烁，并且会有两条辉煌的纯能量光翼从你的后背延展，在本场景内你的移动速度增加10米。</p><p>天罚阿斯莫<br> 天罚阿斯莫的体内永远充满了剧烈燃烧的神圣怒火。这为他们提供了强大的渴望去摧毁邪恶——那是一种渴望，最好的情况他将无所畏惧，最坏的情况下他与罪恶玉石共焚。许多天罚阿斯莫头带面具以此遮挡视界并控制这股力量，只有在战斗中他们才会揭开面罩。</p><p>光辉焚化：你可以使用一个移动动作使你体内的神圣能量解除拘束。灼热的光芒将以你为中心辐射，从你的口中和眼中涌动而出，只消顷刻就会将你焚毁，你的转变持续一个场景或直到你以一个自由动作中止。在开启【光辉焚化】后，你的近战攻击将额外附带1个附加成功。</p><p>堕落阿斯莫<br> 一个阿斯莫在青年时期接触了黑暗力量或是在成人之前转向邪恶将会堕落——这些阿斯莫内心的光芒已经被黑暗所取代。堕落阿斯莫在剧情世界中视为【黑暗生物】，他们憎恶那些自以为是的正义，不择手段的引诱众生于自己一同堕落，尤其视那些善良而高尚的人。</p><p>黑暗引诱：你可以使用一个整轮动作来解放你内在的腐败力量。你的眼睛将变为两个漆黑的池，一对幽灵般的骨翅将从你的身后展开。<br> 你的转变持续一场景或直到你以一个自由动作中止。<br> 展开转变后，你的攻击附带1点不可豁免的亢奋不良点数，可叠加。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
